import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import API from "../api";

export default function AddProduct() {
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [price, setPrice] = useState("");
  const [isAvailable, setIsAvailable] = useState(true);
  const [onOffer, setOnOffer] = useState(false);
  const [image, setImage] = useState(null);
  const [imagePreview, setImagePreview] = useState(null);
  const [loading, setLoading] = useState(false);
  const [connectionError, setConnectionError] = useState(false);
  const navigate = useNavigate();

  // Check backend connection on component mount
  useEffect(() => {
    checkBackendConnection();
  }, []);

  const checkBackendConnection = async () => {
    try {
      await API.get("/products");
      setConnectionError(false);
    } catch (error) {
      console.error("Backend connection failed:", error);
      setConnectionError(true);
    }
  };

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    setImage(file);
    
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => setImagePreview(e.target.result);
      reader.readAsDataURL(file);
    } else {
      setImagePreview(null);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    
    try {
      // Check if backend is reachable first
      if (connectionError) {
        throw new Error("Backend server is not reachable");
      }

      if (!image) {
        alert("Please select an image");
        return;
      }

      const formData = new FormData();
      formData.append("name", name);
      formData.append("description", description);
      formData.append("price", price);
      formData.append("isAvailable", isAvailable);
      formData.append("onOffer", onOffer);
      formData.append("image", image);

      console.log("Submitting product data...");
      const res = await API.post("/products", formData, {
        headers: {
          "Content-Type": "multipart/form-data",
        },
      });
      
      alert("✅ Product Added: " + res.data.name);
      navigate("/list");
    } catch (err) {
      console.error("Error details:", err);
      
      let errorMessage = "❌ Failed to add product";
      
      if (err.code === 'ERR_NETWORK') {
        errorMessage = "❌ Cannot connect to server. Please ensure:\n" +
                      "1. Backend server is running on http://localhost:5000\n" +
                      "2. CORS is properly configured on the backend\n" +
                      "3. No firewall is blocking the connection";
      } else if (err.response) {
        errorMessage = `❌ Server Error: ${err.response.data?.message || err.response.statusText}`;
      } else if (err.message) {
        errorMessage = `❌ Error: ${err.message}`;
      }
      
      alert(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto">
      {/* Page Header */}
      <div className="text-center mb-8">
        <h1 className="text-4xl font-bold text-gray-900 mb-2">Add New Product</h1>
        <p className="text-gray-600 text-lg">Fill in the details to add a new product to your inventory</p>
      </div>

      {connectionError && (
        <div className="bg-red-50 border border-red-200 text-red-800 px-6 py-4 rounded-xl mb-6">
          <div className="flex items-center space-x-2">
            <span className="text-xl">⚠️</span>
            <div>
              <strong>Connection Error:</strong> Cannot connect to backend server. 
              Make sure your backend is running on http://localhost:5000
              <button 
                onClick={checkBackendConnection}
                className="ml-2 text-red-900 underline hover:no-underline font-medium"
              >
                Retry Connection
              </button>
            </div>
          </div>
        </div>
      )}
      
      <div className="bg-white rounded-2xl shadow-xl p-8">
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="mb-4">
            <label className="block text-gray-700 text-sm font-bold mb-2">
              Product Name
            </label>
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="w-full px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
              placeholder="Enter product name"
              required
            />
          </div>

          <div className="mb-4">
            <label className="block text-gray-700 text-sm font-bold mb-2">
              Description
            </label>
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              className="w-full px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
              rows="3"
              placeholder="Enter product description"
              required
            />
          </div>

          <div className="mb-4">
            <label className="block text-gray-700 text-sm font-bold mb-2">
              Price (PKR)
            </label>
            <input
              type="number"
              value={price}
              onChange={(e) => setPrice(e.target.value)}
              className="w-full px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
              placeholder="Enter product price in PKR"
              min="0"
              step="0.01"
              required
            />
          </div>

          <div className="flex items-center space-x-4 mb-4">
            <label className="flex items-center">
              <input
                type="checkbox"
                checked={isAvailable}
                onChange={(e) => setIsAvailable(e.target.checked)}
                className="mr-2"
              />
              Available
            </label>
            
            <label className="flex items-center">
              <input
                type="checkbox"
                checked={onOffer}
                onChange={(e) => setOnOffer(e.target.checked)}
                className="mr-2"
              />
              On Offer
            </label>
          </div>

          <div className="mb-4">
            <label className="block text-gray-700 text-sm font-bold mb-2">
              Product Image
            </label>
            <input
              type="file"
              onChange={(e) => setImage(e.target.files[0])}
              className="w-full px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
              accept="image/*"
              required
            />
          </div>

          <button
            type="submit"
            className="w-full bg-blue-500 text-white py-2 px-4 rounded-lg hover:bg-blue-600 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            Add Product
          </button>
        </form>
      </div>
    </div>
  );
}
